switch (callbackType)
                {
                    case CallbackType.Kill:
                        tween.onKill = originalCompleteAction;
                        break;
                    case CallbackType.Complete:
                        tween.onComplete = originalCompleteAction;
                        break;
                    case CallbackType.Pause:
                        tween.onPause = originalCompleteAction;
                        break;
                    case CallbackType.Play:
                        tween.onPlay = originalCompleteAction;
                        break;
                    case CallbackType.Rewind:
                        tween.onRewind = originalCompleteAction;
                        break;
                    case CallbackType.StepComplete:
                        tween.onStepComplete = originalCompleteAction;
                        break;
                    default:
                        break;
                }

switch (delayType)
            {
                case DelayType.UnscaledDeltaTime:
                    {
                        return new UniTask(DelayIgnoreTimeScalePromise.Create(delayTimeSpan, delayTiming, cancellationToken, cancelImmediately, out var token), token);
                    }
                case DelayType.Realtime:
                    {
                        return new UniTask(DelayRealtimePromise.Create(delayTimeSpan, delayTiming, cancellationToken, cancelImmediately, out var token), token);
                    }
                case DelayType.DeltaTime:
                default:
                    {
                        return new UniTask(DelayPromise.Create(delayTimeSpan, delayTiming, cancellationToken, cancelImmediately, out var token), token);
                    }
            }

if (source.QueryExpression is SelectExpression subquery
            && TryGetProjection(source, out projection))
        {
            subquery.ApplyProjection();

            var arrayClrType = typeof(IEnumerable<>).MakeGenericType(projection.Type);

            switch (projection)
            {
                case StructuralTypeShaperExpression:
                    array = new ObjectArrayExpression(subquery, arrayClrType);
                    return true;

                // TODO: Temporary hack - need to perform proper derivation of the array type mapping from the element (e.g. for
                // value conversion). #34026.
                case SqlExpression sqlExpression:
                    var arrayTypeMapping = typeMappingSource.FindMapping(arrayClrType);

                    array = new ScalarArrayExpression(subquery, arrayClrType, arrayTypeMapping);
                    return true;
            }
        }

if (includeDiscriminator is IdDiscriminatorMode.EntityType or IdDiscriminatorMode.RootEntityType)
        {
            var discriminator = entityType.GetDiscriminatorValue();
            // If the discriminator is not part of the primary key already, then add it to the Cosmos `id`.
            if (discriminator != null)
            {
                var discriminatorProperty = entityType.FindDiscriminatorProperty();
                if (!primaryKey.Properties.Contains(discriminatorProperty))
                {
                    // Use the actual type for backwards compat, but the base type to allow lookup using ReadItem.
                    return includeDiscriminator is IdDiscriminatorMode.EntityType
                        ? new JsonIdDefinition(properties, entityType, false)
                        : new JsonIdDefinition(properties, entityType.GetRootType(), true);
                }
            }
        }

switch (extensionExpression)
        {
            case EntityQueryRootExpression when _subquery:
                AddTranslationErrorDetails(CosmosStrings.NonCorrelatedSubqueriesNotSupported);
                return QueryCompilationContext.NotTranslatedExpression;

            case FromSqlQueryRootExpression fromSqlQueryRoot:
                var entityType = fromSqlQueryRoot.EntityType;
                var fromSql = new FromSqlExpression(entityType.ClrType, fromSqlQueryRoot.Sql, fromSqlQueryRoot.Argument);
                var alias = _aliasManager.GenerateSourceAlias(fromSql);
                var selectExpression = new SelectExpression(
                    new SourceExpression(fromSql, alias),
                    new StructuralTypeProjectionExpression(new ObjectReferenceExpression(entityType, alias), entityType));
                return CreateShapedQueryExpression(entityType, selectExpression) ?? QueryCompilationContext.NotTranslatedExpression;

            default:
                return base.VisitExtension(extensionExpression);
        }

switch (left, right)
        {
            // Null equality always translates to = null in cosmos, no matter the type of structural type.
            case (StructuralTypeReferenceExpression, SqlConstantExpression { Value: null }):
            case (SqlConstantExpression { Value: null }, StructuralTypeReferenceExpression):
                return RewriteNullEquality(out result);

            case (StructuralTypeReferenceExpression { StructuralType: IEntityType }, _):
            case (_, StructuralTypeReferenceExpression { StructuralType: IEntityType }):
                return TryRewriteEntityEquality(out result);

            case (StructuralTypeReferenceExpression { StructuralType: IComplexType }, _):
            case (_, StructuralTypeReferenceExpression { StructuralType: IComplexType }):
                return TryRewriteComplexTypeEquality(out result);

            default:
                result = null;
                return false;
        }

switch (structuralProperty)
        {
            case INavigation navigation:
                structuralType = navigation.TargetEntityType;
                propertyName = navigation.TargetEntityType.GetContainingPropertyName()
                    ?? throw new InvalidOperationException(
                        CosmosStrings.NavigationPropertyIsNotAnEmbeddedEntity(
                            navigation.DeclaringEntityType.DisplayName(), navigation.Name));
                break;
            case IComplexProperty complexProperty:
                structuralType = complexProperty.ComplexType;
                propertyName = complexProperty.GetJsonPropertyName();
                break;
            default:
                throw new UnreachableException($"Unexpected structural property type: {structuralProperty.GetType().FullName}");
        }

switch (structuralProperty)
        {
            case INavigation navigation:
                targetType = navigation.TargetEntityType;
                propertyName = navigation.TargetEntityType.GetContainingPropertyName()
                    ?? throw new InvalidOperationException(
                        CosmosStrings.NavigationPropertyIsNotAnEmbeddedEntity(
                            navigation.DeclaringEntityType.DisplayName(), navigation.Name));
                break;
            case IComplexProperty complexProperty:
                targetType = complexProperty.ComplexType;
                propertyName = complexProperty.GetJsonPropertyName();
                break;
            default:
                throw new UnreachableException($"Unexpected structural property type: {structuralProperty.GetType().FullName}");
        }

if (!_navigationExpressionsMap.TryGetValue(navigation, out var expression))
        {
            // TODO: Unify ObjectAccessExpression and ObjectArrayAccessExpression
            expression = navigation.IsCollection
                ? new StructuralTypeShaperExpression(
                    navigation.TargetEntityType,
                    new ObjectArrayAccessExpression(Object, navigation),
                    nullable: true)
                : new StructuralTypeShaperExpression(
                    navigation.TargetEntityType,
                    new StructuralTypeProjectionExpression(new ObjectAccessExpression(Object, navigation), navigation.TargetEntityType),
                    nullable: !navigation.ForeignKey.IsRequiredDependent);

            _navigationExpressionsMap[navigation] = expression;
        }

if (!_complexPropertyExpressionsMap.TryGetValue(complexProperty, out var expression))
        {
            // TODO: Unify ObjectAccessExpression and ObjectArrayAccessExpression
            expression = complexProperty.IsCollection
                ? new StructuralTypeShaperExpression(
                    complexProperty.ComplexType,
                    new ObjectArrayAccessExpression(Object, complexProperty),
                    nullable: true)
                : new StructuralTypeShaperExpression(
                    complexProperty.ComplexType,
                    new StructuralTypeProjectionExpression(new ObjectAccessExpression(Object, complexProperty), complexProperty.ComplexType),
                    nullable: complexProperty.IsNullable);

            _complexPropertyExpressionsMap[complexProperty] = expression;
        }

switch (inExpression)
        {
            case { ValuesParameter: { } parameter }:
                valuesTypeMapping = parameter.TypeMapping;
                break;

            case { Values: { } values }:
                // Note: there could be conflicting type mappings inside the values; we take the first.
                foreach (var value in values)
                {
                    if (value.TypeMapping is null)
                    {
                        missingTypeMappingInValues = true;
                    }
                    else
                    {
                        valuesTypeMapping = value.TypeMapping;
                    }
                }

                break;

            default:
                throw new ArgumentOutOfRangeException();
        }

foreach (var updateEntry in batch.UpdateEntries)
        {
            var document = updateEntry.Operation != CosmosCudOperation.Delete ? updateEntry.DocumentSource.Serialize(updateEntry.Entry) : default;

            // With AutoTransactionBehavior.Always, AddToTransaction will always return true.
            if (!AddToTransaction(transaction, updateEntry, document))
            {
                yield return transaction;
                transaction = _cosmosClient.CreateTransactionalBatch(batch.Key.ContainerId, batch.Key.PartitionKeyValue, checkSize);
                AddToTransaction(transaction, updateEntry, document);
                continue;
            }

            if (checkSize && transaction.Entries.Count == maxOperationsPerBatch)
            {
                yield return transaction;
                transaction = _cosmosClient.CreateTransactionalBatch(batch.Key.ContainerId, batch.Key.PartitionKeyValue, checkSize);
            }
        }

if (structuralType is IEntityType entityType)
        {
            foreach (var navigation in entityType.GetNavigations())
            {
                // skip back-references to the parent
                var fk = navigation.ForeignKey;
                if (!fk.IsOwnership || navigation.IsOnDependent)
                {
                    continue;
                }

                var jsonPropertyName = navigation.TargetEntityType.GetContainingPropertyName();

                Debug.Assert(jsonPropertyName != null, "Containing property name should not be null on owned navigation.");

                writer.WritePropertyName(jsonPropertyName);

                WriteJsonStructuralPropertyValue(writer, entry, navigation, navigation.TargetEntityType, navigation.IsCollection);
            }
        }

foreach (var tp in methodSymbol.TypeParameters)
            {
                if (_getAllowsRefLikeType?.Invoke(tp) == true)
                {
                    // 'allows ref struct' anti-constraint is not supported because the generated code stores
                    // parameters in fields and cannot hold ref struct type arguments.
                    Diag(DiagDescriptors.LoggingMethodHasAllowsRefStructConstraint, method.Identifier.GetLocation());
                    keepMethod = false;
                    break;
                }

                lm.TypeParameters.Add(new LoggingMethodTypeParameter
                {
                    Name = tp.Name,
                    Constraints = GetTypeParameterConstraints(tp),
                });
            }

switch (parameter.Member)
            {
                case ConstructorInfo ctor:
                    var metaCtor = (ConstructorInfo)GetMemberMetadataDefinition(ctor);
                    metaMember = metaCtor;
                    metaParameter = GetMetaParameter(metaCtor, parameter);
                    break;

                case MethodInfo method:
                    MethodInfo metaMethod = GetMethodMetadataDefinition(method);
                    metaMember = metaMethod;
                    metaParameter = string.IsNullOrEmpty(parameter.Name) ? metaMethod.ReturnParameter : GetMetaParameter(metaMethod, parameter);
                    break;

                default:
                    return;
            }

if (parameters != null)
        {
            foreach (var parameter in parameters)
            {
                var p = parameter as ControllerParameterDescriptor;

                if (p != null)
                {
                    var dataClassificationAttributes = p.ParameterInfo.GetCustomAttributes(_dataClassificationAttributeType, true);

                    if (dataClassificationAttributes.Length > 0)
                    {
                        var classification = ((DataClassificationAttribute)dataClassificationAttributes[0]).Classification;
                        parametersToRedact[p.ParameterInfo.Name!] = classification;
                    }
                }
            }
        }

if (update.AdditionalProperties is not null)
        {
            if (update.MessageId is { Length: > 0 })
            {
                if (message.AdditionalProperties is null)
                {
                    message.AdditionalProperties = new(update.AdditionalProperties);
                }
                else
                {
                    message.AdditionalProperties.SetAll(update.AdditionalProperties);
                }
            }
            else
            {
                if (response.AdditionalProperties is null)
                {
                    response.AdditionalProperties = new(update.AdditionalProperties);
                }
                else
                {
                    response.AdditionalProperties.SetAll(update.AdditionalProperties);
                }
            }
        }

while (toCheck.TryPop(out Exception? current))
        {
            // To avoid infinite loops, ignore exceptions that were already seen.
            if (seen.Add(current))
            {
                if (current is AggregateException aggregateException)
                {
                    foreach (var innerException in aggregateException.InnerExceptions)
                    {
                        toCheck.Push(innerException);
                    }
                }
                else if (current is OperationCanceledException)
                {
                    containsAtLeastOneCancellation = true;
                }
                else
                {
                    return false;
                }
            }
        }

if (toolCalls.Any(t => !toolDefinitionNames.Contains(t.Name)))
        {
            if (context is null)
            {
                metric.AddDiagnostics(
                    EvaluationDiagnostic.Error(
                        $"The {nameof(modelResponse)} supplied for evaluation contained calls to tools that were not supplied via {nameof(IntentResolutionEvaluatorContext)}."));
            }
            else
            {
                metric.AddDiagnostics(
                    EvaluationDiagnostic.Error(
                        $"The {nameof(modelResponse)} supplied for evaluation contained calls to tools that were not included in the supplied {nameof(IntentResolutionEvaluatorContext)}."));
            }

            return result;
        }

if (toolCalls.Any(t => !toolDefinitionNames.Contains(t.Name)))
        {
            if (context is null)
            {
                metric.AddDiagnostics(
                    EvaluationDiagnostic.Error(
                        $"The {nameof(modelResponse)} supplied for evaluation contained calls to tools that were not supplied via {nameof(TaskAdherenceEvaluatorContext)}."));
            }
            else
            {
                metric.AddDiagnostics(
                    EvaluationDiagnostic.Error(
                        $"The {nameof(modelResponse)} supplied for evaluation contained calls to tools that were not included in the supplied {nameof(TaskAdherenceEvaluatorContext)}."));
            }

            return result;
        }

if (options is ContentSafetyChatOptions contentSafetyChatOptions)
        {
            ValidateSingleMessage(messages);
            string payload = messages.Single().Text;

            string annotationResult =
                await _service.AnnotateAsync(
                    payload,
                    contentSafetyChatOptions.AnnotationTask,
                    contentSafetyChatOptions.EvaluatorName,
                    cancellationToken).ConfigureAwait(false);

            return new ChatResponse(new ChatMessage(ChatRole.Assistant, annotationResult))
            {
                ModelId = ModelInfo.KnownModels.AzureAIFoundryEvaluation
            };
        }
        else
        {
            ValidateOriginalChatClientNotNull();

            return await _originalChatClient.GetResponseAsync(
                messages,
                options,
                cancellationToken).ConfigureAwait(false);
        }

if (messages.ContainsImageWithSupportedFormat() || modelResponse.ContainsImageWithSupportedFormat())
        {
            EvaluationResult imageResult =
                await EvaluateContentSafetyAsync(
                    chatClient,
                    messages,
                    modelResponse,
                    contentSafetyServicePayloadFormat: ContentSafetyServicePayloadFormat.Conversation.ToString(),
                    includeMetricNamesInContentSafetyServicePayload: false,
                    cancellationToken: cancellationToken).ConfigureAwait(false);

            foreach (EvaluationMetric imageMetric in imageResult.Metrics.Values)
            {
                result.Metrics.Add(imageMetric.Name, imageMetric);
            }
        }

if (_sessionClient is not null)
        {
            // Allow callers to provide a pre-configured SDK-specific options instance.
            object? rawOptions = options.RawRepresentationFactory?.Invoke();

            if (rawOptions is Sdk.RealtimeTranscriptionSessionOptions rawTransOptions)
            {
                await _sessionClient.ConfigureTranscriptionSessionAsync(rawTransOptions, cancellationToken).ConfigureAwait(false);
            }
            else if (options.SessionKind == RealtimeSessionKind.Transcription)
            {
                var transOpts = BuildTranscriptionSessionOptions(options);
                await _sessionClient.ConfigureTranscriptionSessionAsync(transOpts, cancellationToken).ConfigureAwait(false);
            }
            else
            {
                var convOpts = BuildConversationSessionOptions(options, rawOptions as Sdk.RealtimeConversationSessionOptions);
                await _sessionClient.ConfigureConversationSessionAsync(convOpts, cancellationToken).ConfigureAwait(false);
            }
        }

if (!SchemaRepresentsObject(schema))
        {
            // For non-object-representing schemas, we wrap them in an object schema, because all
            // the real LLM providers today require an object schema as the root. This is currently
            // true even for providers that support native structured output.
            isWrappedInObject = true;
            schema = JsonSerializer.SerializeToElement(new JsonObject
            {
                { "$schema", "https://json-schema.org/draft/2020-12/schema" },
                { "type", "object" },
                { "properties", new JsonObject { { "data", JsonElementToJsonNode(schema) } } },
                { "additionalProperties", false },
                { "required", new JsonArray("data") },
            }, AIJsonUtilities.DefaultOptions.GetTypeInfo(typeof(JsonObject)));
            responseFormat = ChatResponseFormat.ForJsonSchema(schema, responseFormat.SchemaName, responseFormat.SchemaDescription);
        }

try
        {
            setCurrentContext(context);
            var result = await InstrumentedInvokeFunctionAsync(context, cancellationToken).ConfigureAwait(false);
            if (context.Terminate)
            {
                FunctionInvocationLogger.LogFunctionRequestedTermination(_logger, callContent.Name);
            }

            return new(context.Terminate, FunctionInvocationStatus.RanToCompletion, callContent, result, exception: null);
        }
        catch (Exception ex) when (captureExceptions && !cancellationToken.IsCancellationRequested)
        {
            return new(terminate: false, FunctionInvocationStatus.Exception, callContent, result: null, exception: ex);
        }
        finally
        {
            setCurrentContext(null);
        }

foreach (var fcc in functionCallContents)
        {
            AIFunctionDeclaration? tool = FindTool(fcc.Name, AdditionalTools, _innerSession.Options?.Tools);
            if (tool is not null)
            {
                if (tool is not AIFunction)
                {
                    // The tool exists but is not invocable (e.g. AIFunctionDeclaration only).
                    // Always terminate so the caller can handle the call.
                    FunctionInvocationLogger.LogNonInvocableFunction(_logger, fcc.Name);
                    return true;
                }
            }
            else if (TerminateOnUnknownCalls)
            {
                // The tool is completely unknown. If configured, terminate.
                FunctionInvocationLogger.LogFunctionNotFound(_logger, fcc.Name);
                return true;
            }
        }

if (string.IsNullOrWhiteSpace(_endpointName))
        {
            // Treat the scheme as the endpoint name and use the first section with a matching endpoint name which exists
            endpointName = DefaultEndpointName;
            ReadOnlySpan<string> candidateNames = [DefaultEndpointName, .. _schemes];
            foreach (var scheme in candidateNames)
            {
                var candidate = section.GetSection(scheme);
                if (candidate.Exists())
                {
                    endpointName = scheme;
                    namedSection = candidate;
                    break;
                }
            }
        }
        else
        {
            // Use the section corresponding to the endpoint name.
            endpointName = _endpointName;
            namedSection = section.GetSection(_endpointName);
        }

while (true)
        {
            var resolver = _resolvers.GetOrAdd(
                key,
                static (name, self) => self.CreateResolver(name),
                this);

            var (valid, endpoint) = await resolver.TryGetEndpointAsync(request, cancellationToken).ConfigureAwait(false);
            if (valid)
            {
                if (endpoint is null)
                {
                    throw new InvalidOperationException($"Unable to resolve endpoint for service {resolver.ServiceName}");
                }

                return endpoint;
            }
            else
            {
                _resolvers.TryRemove(KeyValuePair.Create(resolver.ServiceName, resolver));
            }
        }

if (_singleFullTextSearchProperty is null)
        {
            // If text data property name is not provided, check if a single full text indexed text property exists or throw otherwise.
            var fullTextStringProperties = DataProperties
                .Where(l => l.Type == typeof(string) && l.IsFullTextIndexed)
                .ToList();

            // If text data property name is not provided, check if a single full text indexed text property exists or throw otherwise.
            _singleFullTextSearchProperty = fullTextStringProperties switch
            {
                [var singleProperty] => singleProperty,
                { Count: 0 } => throw new InvalidOperationException($"The '{_recordType.Name}' type does not have any text data properties that have full text indexing enabled."),
                _ => throw new InvalidOperationException($"The '{_recordType.Name}' type has multiple text data properties that have full text indexing enabled, please specify your chosen property via options."),
            };
        }

try
            {
                if (message == null)
                    throw new ArgumentNullException(nameof(message));

                if (string.IsNullOrWhiteSpace(message.ReceiptHandle))
                    throw new ArgumentNullException(nameof(message.ReceiptHandle));

                if (string.IsNullOrWhiteSpace(queueUrl))
                    throw new InvalidOperationException("Queue not initialized");

                await sqsClient.DeleteMessageAsync(
                    new DeleteMessageRequest { QueueUrl = queueUrl, ReceiptHandle = message.ReceiptHandle });
            }
            catch (Exception exc)
            {
                ReportErrorAndRethrow(exc, "DeleteMessage");
            }
